import { TextControl } from '@wordpress/components';

import { __ } from '@wordpress/i18n';

const ProductListBestsellers = (props) => {

    let content = [], button, layout;

    if(props.attributes.list_layout_selected) {
        button = <button
            type="button"
            disabled={ !props.attributes.keywords || !props.attributes.list_layout }
            className="hostinger-block-button hostinger-block-button--is-normal hostinger-block-button--is-primary"
            onClick={ () => props.setAttributes({ ready: true })}
        >
            { __('Add best-sellers', 'hostinger-affiliate-plugin') }

        </button>

        layout = <>
            <div
                className="hostinger-block-product-selector__layout-select-title"
            >
                { __( 'Choose the layout of your product list', 'hostinger-affiliate-plugin' ) }
            </div>
            <div
                className="hostinger-block-product-selector__layout-grid"
            >
                { Object.entries(props.list_layouts).map((type, index) => {
                    return (
                        <div
                            key="index"
                            className={`hostinger-block-product-selector__layout-item ${(props.attributes.list_layout == type[1].value ? 'hostinger-block-product-selector__layout-item--is-selected' : '')}`}
                            onClick={ () => props.setAttributes({ list_layout: type[1].value })}
                        >
                            <div className="hostinger-block-product-selector__layout-item-img">
                                <img src={hst_affiliate_data.plugin_url + 'assets/img/' + type[1].image} alt="" />
                            </div>
                            <div className="hostinger-block-product-selector__layout-item-title">
                                { type[1].label }
                            </div>
                        </div>
                    )
                })}
            </div>
        </>
    } else {
        button = <button
            type="button"
            disabled={ !props.attributes.keywords }
            onClick={ () => props.setAttributes({ list_layout_selected: true })}
            className="hostinger-block-button hostinger-block-button--is-normal hostinger-block-button--is-primary">
            { __('Continue', 'hostinger-affiliate-plugin') }

        </button>
    }

    content.push(
        <>
            <div
                className="hostinger-block-product-selector__back-text-wrap"
                onClick={ () => props.setAttributes({
                    product_list_type: '',
                    list_navigation: 'generate_type'
                }) }
                role="button"
            >
                <svg width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <g id="ic_arrow_forward">
                        <path d="M16.6673 9.16668H6.52565L11.184 4.50834L10.0007 3.33334L3.33398 10L10.0007 16.6667L11.1757 15.4917L6.52565 10.8333H16.6673V9.16668Z" fill="#673DE6"/>
                    </g>
                </svg>
                <div className="hostinger-block-product-selector__back-text">
                    { __('How do you want to generate the list of the products?', 'hostinger-affiliate-plugin') }
                </div>
            </div>
            <div
                className="hostinger-block-product-selector__heading"
            >
                { __( 'Automatically generate product list', 'hostinger-affiliate-plugin' ) }
            </div>
            <div
                className="hostinger-block-product-selector__sub-heading"
            >
                { __( 'Insert the product keyword, we will show the best-seller products', 'hostinger-affiliate-plugin' ) }
            </div>
            <TextControl
                ref= { input => input && '' === props.attributes.keywords && input.focus() }
                key = "hostinger-block-product-selector__product-asin-field"
                className = "hostinger-block-product-selector__product-asin-field"
                value = { props.attributes.keywords }
                placeholder = { __( 'Enter product keywords here, example: corsair rgb keyboard', 'hostinger-affiliate-plugin') }
                onChange = { (value) => props.setAttributes( { keywords: value } ) }
            />
            <div className="hostinger-block-product-selector__snackbar">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none">
                    <path d="M12 2C6.477 2 2 6.477 2 12C2 17.523 6.477 22 12 22C17.523 22 22 17.523 22 12C22 6.477 17.523 2 12 2ZM13 17H11V11H13V17ZM13 9H11V7H13V9Z" fill="#727586"/>
                </svg>
                { __('Don’t worry. You can edit the layout and product in the Block configuration in the right sidebar anytime.', 'hostinger-affiliate-plugin') }
            </div>
            { layout }
            <div className="hostinger-block-product-selector__add-product-wrap">
                { button }
            </div>
        </>
    )

    return (
        <>
            <div className="hostinger-block-product-selector">
                <div className="hostinger-block-product-selector__divider"></div>
                { content }
            </div>
        </>
    );

}
export default ProductListBestsellers